const config = {
  "previewFeatures": [],
  "clientVersion": "7.7.0",
  "engineVersion": "75cbdc1eb7150937890ad5465d861175c6624711",
  "activeProvider": "postgresql",
  "inlineSchema": "generator client {\n  provider = \"prisma-client-js\"\n  output   = \"../generated/prisma\" // Required in v7\n}\n\n// organisationId\ndatasource db {\n  provider = \"postgresql\"\n  // Note: No 'url' here anymore\n}\n\n//\n// ─────────────────────────────────────────────\n// 1. ORGANISATION (MULTI-TENANT ROOT)\n// ─────────────────────────────────────────────\n//\n\nmodel Organisation {\n  id           String   @id @default(cuid())\n  name         String\n  slug         String   @unique\n  logoUrl      String?\n  contactEmail String?\n  contactPhone String?\n  address      String?\n  createdAt    DateTime @default(now())\n\n  // Relations (Using the updated PriceList name)\n  outboxEvents   OutboxEvent[]\n  users          User[]\n  staff          Staff[]\n  clients        Client[]\n  jobs           Job[]\n  stockItems     StockItem[]\n  stockMovements StockMovement[]\n  prices         PriceList[]\n  deliveries     Delivery[]\n  b2bPushes      B2BPush[]\n  auditLogs      AuditLog[]\n\n  // Performance Indexes\n  @@index([name])\n  @@index([createdAt])\n}\n\n//\n// ─────────────────────────────────────────────\n// 2. AUTH / USERS / RBAC\n// ─────────────────────────────────────────────\n//\n\nmodel OutboxEvent {\n  id      String @id @default(cuid())\n  type    String\n  payload Json\n  orgId   String\n\n  // Add this to link it properly\n  organisation Organisation @relation(fields: [orgId], references: [id])\n\n  status    String   @default(\"PENDING\")\n  createdAt DateTime @default(now())\n\n  // Add this index for performance\n  @@index([orgId])\n  @@index([status])\n}\n\nenum UserRole {\n  ADMIN\n  OPERATOR\n  CASHIER\n  GUEST\n  GRAPHIC_DESIGNER\n}\n\nmodel User {\n  id           String       @id @default(cuid())\n  orgId        String\n  organisation Organisation @relation(fields: [orgId], references: [id])\n\n  name      String\n  email     String   @unique // @unique already creates a high-performance index\n  role      UserRole\n  avatarUrl String?\n  createdAt DateTime @default(now())\n\n  staffProfile Staff?\n\n  // INDEXING:\n  @@index([orgId]) // Critical: Ensures users stay within their organization\n  @@index([role]) // Fast lookup for global or org-level permission checks\n  @@index([createdAt]) // Useful for sorting the newest sign-ups\n}\n\n//\n// ─────────────────────────────────────────────\n// 3. STAFF\n// ─────────────────────────────────────────────\n//\n\nmodel Staff {\n  id           String       @id @default(cuid())\n  orgId        String\n  organisation Organisation @relation(fields: [orgId], references: [id])\n\n  userId String @unique\n  user   User   @relation(fields: [userId], references: [id])\n\n  name           String\n  role           UserRole\n  phone          String?\n  avatarUrl      String?\n  specialisation String?\n  isActive       Boolean  @default(true)\n\n  assignedJobs Job[] @relation(\"StaffJobs\")\n\n  createdAt DateTime @default(now())\n\n  // INDEXING:\n  @@index([orgId]) // Standard for multi-tenant isolation\n  @@index([name]) // Fast lookup for team lists and dropdowns\n  @@index([isActive]) // Important for filtering out former employees\n  @@index([role]) // Useful for permission checks and role-based filtering\n  @@index([orgId, isActive]) // Compound index for loading the active team list\n}\n\n//\n// ─────────────────────────────────────────────\n// 4. CLIENTS\n// ─────────────────────────────────────────────\n//\n\nenum ClientType {\n  PRIVATE\n  COMPANY\n}\n\nmodel Client {\n  id    String @id @default(cuid())\n  orgId String\n\n  type        ClientType\n  name        String\n  companyName String?\n  email       String?\n  phone       String\n  location    String?\n\n  profilePictureUrl String?\n\n  isNew         Boolean @default(true)\n  recentStaffId String?\n\n  lastJobId            String?\n  lastJobDate          DateTime?\n  totalJobs            Int       @default(0)\n  mostPrintedServiceId String?\n\n  notes     String?\n  jobs      Job[]\n  createdAt DateTime @default(now())\n\n  organisation Organisation @relation(fields: [orgId], references: [id])\n\n  @@index([orgId])\n  @@index([orgId, phone])\n  @@index([orgId, name])\n  @@index([orgId, lastJobDate])\n  @@index([orgId, totalJobs])\n  @@index([recentStaffId])\n  @@index([mostPrintedServiceId])\n  @@index([lastJobId])\n}\n\n//\n// ─────────────────────────────────────────────\n// 5. PRICE LIST\n// ─────────────────────────────────────────────\n//\n\nenum ServiceUnit {\n  sqft\n  sqm\n  sqcm\n  inch\n  ft\n  yd\n  mm\n  cm\n  m\n  meter\n  pack\n  piece\n  roll\n  box\n  ream\n  bottle\n  liter\n  hour\n  PER_PAGE\n  PER_100\n  PER_SQ_METER\n  PER_SET\n  PER_YARD\n}\n\nmodel PriceList {\n  id           String       @id @default(cuid())\n  orgId        String\n  organisation Organisation @relation(fields: [orgId], references: [id])\n\n  name      String\n  category  String\n  unit      ServiceUnit\n  costPrice Float?\n  priceGHS  Float\n\n  // 🔥 FORMAL RELATION: Connects PriceList to the StockItem table\n  // This ensures the \"Joinery\" is visible in Prisma Studio and enforced by DB\n  stockRefId String?\n  stockItem  StockItem? @relation(fields: [stockRefId], references: [id])\n\n  isActive  Boolean  @default(true)\n  updatedAt DateTime @updatedAt\n\n  // INDEXING:\n  @@index([orgId])\n  @@index([category])\n  @@index([isActive])\n  @@index([stockRefId])\n  @@index([orgId, isActive])\n}\n\n//\n// ─────────────────────────────────────────────\n// 6. STOCK\n// ─────────────────────────────────────────────\n//\n\nmodel StockItem {\n  id           String       @id @default(cuid())\n  orgId        String\n  organisation Organisation @relation(fields: [orgId], references: [id])\n\n  name              String\n  unit              String\n  totalRemaining    Float\n  lowStockThreshold Float\n  lastUnitCost      Float\n  lastRestockedAt   DateTime?\n\n  createdAt      DateTime        @default(now())\n  stockMovements StockMovement[]\n\n  // 🔥 THE FIX: Add the opposite relation field\n  // This allows one StockItem to be linked to multiple PriceList entries\n  prices PriceList[]\n\n  // INDEXING:\n  @@index([orgId])\n  @@index([name])\n  @@index([totalRemaining])\n  @@index([lastRestockedAt])\n}\n\nmodel RestockRecord {\n  id          String   @id @default(cuid())\n  stockItemId String\n  quantity    Float\n  unitCost    Float\n  totalCost   Float\n  recordedBy  String\n  date        DateTime @default(now())\n\n  // INDEXING:\n  @@index([stockItemId]) // Critical for viewing the restock history of a specific item\n  @@index([date(sort: Desc)]) // Optimized for \"Recent Restocks\" logs (newest first)\n  @@index([recordedBy]) // Useful for auditing who logged which inventory update\n}\n\nmodel StockMovement {\n  id String @id @default(cuid())\n\n  orgId        String\n  organisation Organisation @relation(fields: [orgId], references: [id])\n\n  stockItemId String\n  stockItem   StockItem @relation(fields: [stockItemId], references: [id])\n\n  type StockMovementType\n\n  quantity Float\n  unitCost Float?\n\n  // useful for traceability (job, restock, waste, adjustment)\n  referenceId   String?\n  referenceType String? // \"JOB\" | \"RESTOCK\" | \"WASTE\" | \"MANUAL\"\n\n  note String?\n\n  createdBy String\n  createdAt DateTime @default(now())\n\n  // INDEXING\n  @@index([orgId])\n  @@index([stockItemId])\n  @@index([type])\n  @@index([createdAt(sort: Desc)])\n  @@index([referenceId])\n}\n\nenum StockMovementType {\n  RESTOCK\n  DEDUCT\n  WASTE\n  ADJUST\n}\n\n//\n// ─────────────────────────────────────────────\n// 7. JOB ENGINE\n// ─────────────────────────────────────────────\n//\n\nenum JobStatus {\n  PENDING\n  IN_PROGRESS\n  QUALITY_CHECK\n  READY_FOR_PICKUP\n  COMPLETED\n  CANCELLED\n  PAUSED\n}\n\nenum PaymentStatus {\n  UNPAID\n  PARTIAL\n  PAID\n}\n\nmodel Job {\n  id           String       @id @default(cuid())\n  orgId        String\n  organisation Organisation @relation(fields: [orgId], references: [id])\n\n  clientId String\n  client   Client @relation(fields: [clientId], references: [id])\n\n  serviceId   String\n  serviceName String\n\n  quantity Float\n  width    Float?\n  height   Float?\n  unit     String?\n\n  totalPrice   Float\n  costPrice    Float?\n  profitMargin Float?\n\n  materialUsed    Float?\n  materialWastage Float?\n\n  status        JobStatus     @default(PENDING)\n  paymentStatus PaymentStatus @default(UNPAID)\n  isPaid        Boolean       @default(false)\n\n  paymentRef String?\n\n  assignedStaffId String?\n  assignedStaff   Staff?  @relation(\"StaffJobs\", fields: [assignedStaffId], references: [id])\n\n  deliveryId String?\n\n  notes String?\n\n  b2bPushId String?\n  b2bPush   B2BPush? @relation(fields: [b2bPushId], references: [id])\n\n  createdAt   DateTime   @default(now())\n  updatedAt   DateTime   @updatedAt\n  completedAt DateTime?\n  deliveries  Delivery[]\n\n  // INDEXING:\n  @@index([orgId]) // Standard isolation\n  @@index([clientId]) // Fast lookup for \"all jobs for this customer\"\n  @@index([status]) // Critical for \"Production Board\" views (Pending vs Printing)\n  @@index([paymentStatus]) // Essential for \"Unpaid Jobs\" financial reports\n  @@index([assignedStaffId]) // Useful for \"My Tasks\" view for staff members\n  @@index([createdAt(sort: Desc)]) // Optimized for the main Dashboard (newest first)\n  @@index([orgId, status]) // Compound index for lightning-fast Kanban boards\n  @@index([b2bPushId])\n}\n\n//\n// ─────────────────────────────────────────────\n// 8. DELIVERY\n// ─────────────────────────────────────────────\n//\n\nenum DeliveryType {\n  PHYSICAL_PICKUP\n  PRINTER_DELIVERY\n  CLIENT_COURIER\n}\n\nenum DeliveryStatus {\n  PENDING\n  SCHEDULED\n  OUT_FOR_DELIVERY\n  DELIVERED\n  PAUSED\n  FAILED\n}\n\nmodel Delivery {\n  id           String       @id @default(cuid())\n  orgId        String\n  organisation Organisation @relation(fields: [orgId], references: [id])\n\n  jobId String\n  job   Job    @relation(fields: [jobId], references: [id])\n\n  clientId String // Should likely have a relation to the Client model too\n\n  type   DeliveryType\n  status DeliveryStatus @default(PENDING)\n\n  scheduledDate DateTime?\n  deliveredAt   DateTime?\n\n  handledBy String?\n  address   String?\n  notes     String?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // INDEXING:\n  @@index([orgId]) // Standard multi-tenant isolation\n  @@index([jobId]) // Fast lookup for a specific Job's delivery status\n  @@index([status]) // Critical for \"Pending\" vs \"Delivered\" dispatch views\n  @@index([scheduledDate]) // Optimized for the \"Deliveries for Today\" calendar view\n  @@index([clientId]) // Useful for viewing a specific client's delivery history\n}\n\n//\n// ─────────────────────────────────────────────\n// 9. PAYMENTS\n// ─────────────────────────────────────────────\n//\n\nenum PaymentMethod {\n  CASH\n  MOMO\n  BANK_TRANSFER\n  CARD\n  OTHER\n}\n\nmodel Payment {\n  id    String @id @default(cuid())\n  orgId String\n  jobId String\n\n  amount    Float\n  method    PaymentMethod\n  reference String?\n\n  screenshotUrl String?\n\n  confirmedBy String?\n  confirmedAt DateTime @default(now())\n\n  // INDEXING:\n  @@index([orgId]) // Essential for multi-tenant data isolation\n  @@index([jobId]) // Fast lookup for all payments related to a specific Job\n  @@index([method]) // Useful for financial reporting (e.g., total Mobile Money vs Cash)\n  @@index([confirmedAt]) // Optimized for date-range reports (e.g., \"Payments this week\")\n  @@index([reference]) // Allows instant lookup when searching for a transaction ID/Ref\n}\n\n//\n// ─────────────────────────────────────────────\n// 10. B2B LAYER\n// ─────────────────────────────────────────────\n//\n\nenum B2BStatus {\n  PENDING\n  ACCEPTED\n  NEGOTIATING\n  REJECTED\n  COMPLETED\n}\n\nmodel B2BPush {\n  id    String @id @default(cuid())\n  orgId String\n\n  originalJobId String\n\n  clientName  String\n  serviceName String\n  specs       String\n  deadline    DateTime\n\n  suggestedPrice Float?\n\n  status B2BStatus @default(PENDING)\n  jobs   Job[]\n\n  createdAt      DateTime      @default(now())\n  updatedAt      DateTime      @updatedAt\n  organisation   Organisation? @relation(fields: [organisationId], references: [id])\n  organisationId String?\n\n  // INDEXING:\n  @@index([orgId]) // Essential for multi-tenant filtering\n  @@index([status]) // Fast lookup for \"Pending\" or \"Completed\" pushes\n  @@index([originalJobId]) // Critical for linking back to the source Job\n  @@index([deadline]) // Useful for sorting by urgency\n}\n\n//\n// ─────────────────────────────────────────────\n// 11. AUDIT LOG\n// ─────────────────────────────────────────────\n//\n\nmodel AuditLog {\n  id    String @id @default(cuid())\n  orgId String\n\n  action     String\n  entityId   String\n  entityType String\n\n  performedBy String\n\n  meta Json?\n\n  timestamp      DateTime      @default(now())\n  organisation   Organisation? @relation(fields: [organisationId], references: [id])\n  organisationId String?\n\n  // INDEXING:\n  @@index([orgId]) // Fast filtering by Organisation\n  @@index([entityId, entityType]) // Fast lookup for a specific item's history (e.g., all logs for Job X)\n  @@index([timestamp(sort: Desc)]) // Optimized for \"Recent Activity\" feeds\n}\n"
}

